import{CFSimpleAdapter}from"./c-f-simple-adapter.js";class CFMultiAdapter extends CFSimpleAdapter{constructor(e={}){super(Object.assign({layers:[],valueAccessor:e=>e.value},e))}configure(e){return super.configure(e)}conf(){return super.conf()}data(){return this.layers().map(e=>{const r=e.valueAccessor||this._conf.valueAccessor;var a=e.group.all().map(e=>Object.assign(Object.assign({},e),{_value:r(e)}));return{name:e.name,rawData:a}})}layers(){if(this._conf.group){const e={name:this._conf.groupName,group:this._conf.group};return[e].concat(this._conf.layers)}return this._conf.layers}layerByName(r){return this._conf.layers.find(e=>e.name===r)}}export{CFMultiAdapter};